<?php// Inicializa a sessãosession_start();// Verifica se foi passado o ID da conta a ser deletada e se o array existeif (isset($_GET['id']) && isset($_SESSION['saved_accounts'])) {    $targetId = (int)$_GET['id'];    $accounts = $_SESSION['saved_accounts'];    // Percorre as contas salvas para encontrar e remover    foreach ($accounts as $index => $acc) {        if (isset($acc['id']) && $acc['id'] === $targetId) {            // Remove a conta do array            unset($accounts[$index]);            break;        }    }    // Reorganiza os índices do array (para evitar buracos como [0, 2, 3])    // e salva novamente na sessão global    $_SESSION['saved_accounts'] = array_values($accounts);}// Retorna para a página anterior (ou para a home se a anterior não existir)$redirectUrl = isset($_SERVER['HTTP_REFERER']) ? $_SERVER['HTTP_REFERER'] : '/home';header("Location: " . $redirectUrl);exit;?>